import{_ as e,o as t,c as _,a2 as n}from"./chunks/framework.4hJCcvDE.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/bug记录_003-一次更新下载cdn资源异常问题.md","filePath":"blog/bug记录_003-一次更新下载cdn资源异常问题.md","lastUpdated":1784835052000}'),o={name:"blog/bug记录_003-一次更新下载cdn资源异常问题.md"};function r(d,a,p,c,l,s){return t(),_("div",null,[...a[0]||(a[0]=[n('<h2 id="问题描述" tabindex="-1">问题描述 <a class="header-anchor" href="#问题描述" aria-label="Permalink to &quot;问题描述&quot;">​</a></h2><p>某日清晨，策划跑过来说我们的灰度服更新异常，具体表现是在更新界面显示下载文件校验失败。</p><h2 id="解决过程" tabindex="-1">解决过程 <a class="header-anchor" href="#解决过程" aria-label="Permalink to &quot;解决过程&quot;">​</a></h2><p>由于我们的资源已经在对内的下载服务器上进行过更新测试，因此怀疑是灰度用的正式cdn上传的文件有问题，比如未上传完整。运维表示文件已上传完成，一切正常。 于是决定对比一下两个更新服务器上文件差异，因为我们每次都是放出去全量更新包，每个文件都去对比不现实，因此先去查了一下更新日志，找出了这次更新需要下载的文件。再对比了一下下载过程中下载的文件大小，将范围缩小到其中的几张png图片上。尝试将正式服的资源下载回来后发现文件已经损坏，无法用图片编辑器打开，用二进制方式打开看了下，果然文件头已经不是png文件头的形状了。</p><p>到此，当然没有结束，还得帮运维找出可能导致损坏的原因。好吧，我们继续查。 将我们出给运维的更新包内文件解压出来，跟cdn服务器下载回来的资源进行对比。</p><p>源文件文件头为 8950 4e47 0d0a 1a0a 正常的png文件头 目标文件文件头为 8950 4e47 0a1a 0a00 被改了的文件头</p><p>对比了下发现目标文件把源文件的0x0d 0x0a 替换成了 0x0a。 0x0d 0x0a就是\\r\\n，把这替换成\\n，显然就是被当成文本文件给处理了。具体是运维上传时候被处理了还是下载服务器给改了，我们就不得而知了，后续交给运维处理。</p><blockquote><p>未完待续</p></blockquote>',8)])])}const b=e(o,[["render",r]]);export{u as __pageData,b as default};
